import{_ as t,o as a,c as i,a2 as r}from"./chunks/framework.B72_uj9U.js";const p=JSON.parse('{"title":"Chapter 1: Hello, Rust CLI","description":"Set up your Rust development environment and build your first interactive command-line application — the skeleton of a coding agent.","frontmatter":{"title":"Chapter 1: Hello, Rust CLI","description":"Set up your Rust development environment and build your first interactive command-line application — the skeleton of a coding agent."},"headers":[],"relativePath":"learn/project/01-hello-rust-cli/index.md","filePath":"learn/project/01-hello-rust-cli/index.md"}'),o={name:"learn/project/01-hello-rust-cli/index.md"};function l(n,e,s,c,u,d){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="hello-rust-cli" tabindex="-1">Hello, Rust CLI <a class="header-anchor" href="#hello-rust-cli" aria-label="Permalink to &quot;Hello, Rust CLI&quot;">​</a></h1><p>This chapter takes you from zero to a working Rust command-line application. You install the Rust toolchain, learn how Cargo manages projects, and write your first binary. Along the way you pick up the foundational language features you need for every chapter that follows: variables, types, functions, modules, and basic error handling.</p><p>By the end of the chapter you have a small but functional REPL (Read-Eval-Print Loop) that reads user input, processes commands, and prints results. This REPL becomes the skeleton of the coding agent you build throughout the rest of the book. Every concept introduced here is immediately applied to that project so nothing feels abstract.</p><p>The pace assumes you already know how to program in Python (or a similar language). We do not teach general programming concepts; instead we focus on what makes Rust different and why those differences matter for building reliable CLI tools and coding agents.</p><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to &quot;Learning Objectives&quot;">​</a></h2><ul><li>Install Rust and configure a productive development environment with rust-analyzer</li><li>Create, build, and run projects with Cargo — Rust&#39;s all-in-one build tool and package manager</li><li>Understand Rust&#39;s ownership model at an introductory level through variables and types</li><li>Organize code with functions and modules for a clean, scalable project layout</li><li>Handle errors with <code>Result</code> and <code>Option</code> instead of exceptions</li><li>Parse command-line arguments using the <code>clap</code> crate</li><li>Build an interactive REPL that reads from stdin and writes to stdout</li></ul><h2 id="subchapters" tabindex="-1">Subchapters <a class="header-anchor" href="#subchapters" aria-label="Permalink to &quot;Subchapters&quot;">​</a></h2><ol><li><a href="/project/01-hello-rust-cli/01-why-rust.html">Why Rust</a> — understand why Rust is the right choice for building coding agents</li><li><a href="/project/01-hello-rust-cli/02-installing-rust.html">Installing Rust</a> — get your toolchain and editor set up</li><li><a href="/project/01-hello-rust-cli/03-cargo-basics.html">Cargo Basics</a> — learn the build tool you will use every day</li><li><a href="/project/01-hello-rust-cli/04-first-binary.html">First Binary</a> — write, compile, and run your first Rust program</li><li><a href="/project/01-hello-rust-cli/05-project-structure.html">Project Structure</a> — organize your coding-agent project for growth</li><li><a href="/project/01-hello-rust-cli/06-variables-and-types.html">Variables and Types</a> — master immutability, strings, and ownership basics</li><li><a href="/project/01-hello-rust-cli/07-functions-and-modules.html">Functions and Modules</a> — define functions and split code into modules</li><li><a href="/project/01-hello-rust-cli/08-error-handling-basics.html">Error Handling Basics</a> — use <code>Result</code> and <code>Option</code> instead of exceptions</li><li><a href="/project/01-hello-rust-cli/09-cli-argument-parsing.html">CLI Argument Parsing</a> — parse arguments and flags with <code>clap</code></li><li><a href="/project/01-hello-rust-cli/10-reading-user-input.html">Reading User Input</a> — read lines from stdin and handle edge cases</li><li><a href="/project/01-hello-rust-cli/11-building-a-simple-repl.html">Building a Simple REPL</a> — combine everything into a working interactive loop</li><li><a href="/project/01-hello-rust-cli/12-summary-and-exercises.html">Summary and Exercises</a> — review what you learned and practice with exercises</li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Solid programming experience in Python (or another dynamic language)</li><li>A computer running macOS, Linux, or Windows with internet access</li><li>Comfort using a terminal or command prompt</li><li>A code editor you enjoy — VS Code, Zed, Neovim, or any editor that supports rust-analyzer</li></ul>',10)])])}const m=t(o,[["render",l]]);export{p as __pageData,m as default};
